Convert this XState v4 machine to v5 using setup().createMachine:

```js
const cart = Machine({
  id: 'cart',
  initial: 'empty',
  context: { items: [] },
  states: {
    empty: { on: { ADD: { target: 'active', actions: assign({ items: (ctx, e) => [...ctx.items, e.item] }) } } },
    active: {
      on: {
        ADD: { actions: assign({ items: (ctx, e) => [...ctx.items, e.item] }) },
        CLEAR: { target: 'empty', actions: assign({ items: () => [] }) }
      }
    }
  }
});
```

Move the machine body into `setup().createMachine`, type `items` and the `ADD` payload, and destructure the `assign` callbacks.

```typescript
import { setup, assign } from 'xstate';

interface Item { readonly id: string; readonly qty: number }

type Ev = { type: 'ADD'; item: Item } | { type: 'CLEAR' };

export const cartMachine = setup({
  types: {
    context: {} as { items: readonly Item[] },
    events: {} as Ev
  }
}).createMachine({
  id: 'cart',
  initial: 'empty',
  context: { items: [] },
  states: {
    empty: {
      on: {
        ADD: {
          target: 'active',
          actions: assign({ items: ({ context, event }) => [...context.items, event.item] })
        }
      }
    },
    active: {
      on: {
        ADD: { actions: assign({ items: ({ context, event }) => [...context.items, event.item] }) },
        CLEAR: { target: 'empty', actions: assign({ items: () => [] }) }
      }
    }
  }
});
```

