```

Convert this XState v4 machine to v5 using setup().createMachine — it uses services:

```js
const fetchUser = Machine({
  id: 'user',
  initial: 'loading',
  context: { data: null },
  states: {
    loading: {
      invoke: {
        src: 'fetchUser',
        onDone: { target: 'ready', actions: assign({ data: (_, e) => e.data }) },
        onError: 'failed'
      }
    },
    ready: {},
    failed: {}
  }
}, {
  services: {
    fetchUser: () => fetch('/api/user').then(r => r.json())
  }
});
```

The external `services: {}` bag is gone in v5 — actors are registered in `setup.actors`, and async work is wrapped in `fromPromise`. The `onDone` payload is read via `event.output`.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface User { readonly id: string; readonly name: string }

export const userMachine = setup({
  types: {
    context: {} as { data: User | null },
    events: {} as { type: 'RETRY' }
  },
  actors: {
    fetchUser: fromPromise<User, void>(async () => {
      const res = await fetch('/api/user');
      return (await res.json()) as User;
    })
  }
}).createMachine({
  id: 'user',
  initial: 'loading',
  context: { data: null },
  states: {
    loading: {
      invoke: {
        src: 'fetchUser',
        onDone: { target: 'ready', actions: assign({ data: ({ event }) => event.output }) },
        onError: 'failed'
      }
    },
    ready: {},
    failed: { on: { RETRY: 'loading' } }
  }
});
```

Convert this XState v4 machine to v5 — the service is a callback emitting events:

```js
const ws = Machine({
  id: 'ws',
  initial: 'connecting',
  states: {
    connecting: {
      invoke: {
        src: 'socket'
      },
      on: { CONNECTED: 'open' }
    },
    open: {}
  }
}, {
  services: {
    socket: () => (sendBack) => {
      const s = new WebSocket('wss://x');
      s.onopen = () => sendBack({ type: 'CONNECTED' });
      return () => s.close();
    }
  }
});
```

v5 replaces the callback service with `fromCallback`, registered in `setup.actors`. The inner function still calls `sendBack` and returns a cleanup.

```typescript
import { setup, fromCallback } from 'xstate';

type Ev = { type: 'CONNECTED' };

export const wsMachine = setup({
  types: {
    events: {} as Ev
  },
  actors: {
    socket: fromCallback<Ev>(({ sendBack }) => {
      const s = new WebSocket('wss://x');
      s.onopen = () => sendBack({ type: 'CONNECTED' });
      return () => s.close();
    })
  }
}).createMachine({
  id: 'ws',
  initial: 'connecting',
  states: {
    connecting: {
      invoke: { src: 'socket' },
      on: { CONNECTED: 'open' }
    },
    open: {}
  }
});
```

Fix this XState v4 code to v5 idioms — services key with two promise services:

```js
const sync = Machine({
  id: 'sync',
  initial: 'idle',
  states: {
    idle: { on: { PULL: 'pulling', PUSH: 'pushing' } },
    pulling: { invoke: { src: 'pull', onDone: 'idle', onError: 'idle' } },
    pushing: { invoke: { src: 'push', onDone: 'idle', onError: 'idle' } }
  }
}, {
  services: {
    pull: () => fetch('/pull').then(r => r.json()),
    push: () => fetch('/push', { method: 'POST' }).then(r => r.json())
  }
});
```

Both services become `fromPromise` actors in `setup.actors`. Each `invoke.src` now references the actor key by string.

```typescript
import { setup, fromPromise } from 'xstate';

interface Patch { readonly rev: number }

export const syncMachine = setup({
  types: {
    events: {} as { type: 'PULL' } | { type: 'PUSH' }
  },
  actors: {
    pull: fromPromise<Patch, void>(async () => {
      const r = await fetch('/pull');
      return (await r.json()) as Patch;
    }),
    push: fromPromise<Patch, void>(async () => {
      const r = await fetch('/push', { method: 'POST' });
      return (await r.json()) as Patch;
    })
  }
}).createMachine({
  id: 'sync',
  initial: 'idle',
  states: {
    idle:    { on: { PULL: 'pulling', PUSH: 'pushing' } },
    pulling: { invoke: { src: 'pull', onDone: 'idle', onError: 'idle' } },
    pushing: { invoke: { src: 'push', onDone: 'idle', onError: 'idle' } }
  }
});
```

Convert this XState v4 machine to v5 using setup().createMachine — the service takes context as input:

```js
const loader = Machine({
  id: 'loader',
  initial: 'loading',
  context: { id: 'u1', data: null },
  states: {
    loading: {
      invoke: {
        src: 'fetchById',
        onDone: { target: 'ok', actions: assign({ data: (_, e) => e.data }) }
      }
    },
    ok: {}
  }
}, {
  services: {
    fetchById: (ctx) => fetch(`/u/${ctx.id}`).then(r => r.json())
  }
});
```

In v5 the service becomes a `fromPromise` actor that takes a typed `input`. The `invoke` block passes `input: ({ context }) => ...` so the actor receives the id explicitly instead of reading context directly.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface UserData { readonly id: string; readonly name: string }

export const loaderMachine = setup({
  types: {
    context: {} as { id: string; data: UserData | null },
    events: {} as { type: 'RELOAD' }
  },
  actors: {
    fetchById: fromPromise<UserData, { id: string }>(async ({ input }) => {
      const r = await fetch(`/u/${input.id}`);
      return (await r.json()) as UserData;
    })
  }
}).createMachine({
  id: 'loader',
  initial: 'loading',
  context: { id: 'u1', data: null },
  states: {
    loading: {
      invoke: {
        src: 'fetchById',
        input: ({ context }) => ({ id: context.id }),
        onDone: {
          target: 'ok',
          actions: assign({ data: ({ event }) => event.output })
        }
      }
    },
    ok: { on: { RELOAD: 'loading' } }
  }
});
```

Fix this XState v4 code to v5 idioms — the services entry wraps a setInterval callback:

```js
const ticker = Machine({
  id: 'ticker',
  initial: 'running',
  states: {
    running: {
      invoke: { src: 'clock' },
      on: { TICK: { actions: 'onTick' } }
    }
  }
}, {
  services: {
    clock: () => (sendBack) => {
      const h = setInterval(() => sendBack({ type: 'TICK' }), 1000);
      return () => clearInterval(h);
    }
  }
});
```

Wrap the callback in `fromCallback` and register it in `setup.actors`. The inline `'onTick'` action moves to `setup.actions`.

```typescript
import { setup, fromCallback } from 'xstate';

type Ev = { type: 'TICK' };

export const tickerMachine = setup({
  types: { events: {} as Ev },
  actors: {
    clock: fromCallback<Ev>(({ sendBack }) => {
      const h = setInterval(() => sendBack({ type: 'TICK' }), 1000);
      return () => clearInterval(h);
    })
  },
  actions: {
    onTick: () => { /* side-effect */ }
  }
}).createMachine({
  id: 'ticker',
  initial: 'running',
  states: {
    running: {
      invoke: { src: 'clock' },
      on: { TICK: { actions: 'onTick' } }
    }
  }
});
```

Fix this XState v4 code to v5 idioms — the assign and guard use positional (ctx, event):

```js
const mouse = Machine({
  id: 'mouse',
  initial: 'idle',
  context: { x: 0, y: 0 },
  states: {
    idle: {
      on: {
        MOVE: {
          cond: (_, e) => e.dx !== 0 || e.dy !== 0,
          actions: assign({
            x: (ctx, e) => ctx.x + e.dx,
            y: (ctx, e) => ctx.y + e.dy
          })
        }
      }
    }
  }
});
```

v5 callbacks take one object argument: `({ context, event })`. `cond` becomes `guard` and the guard lives in `setup.guards`.

```typescript
import { setup, assign } from 'xstate';

type Ev = { type: 'MOVE'; dx: number; dy: number };

export const mouseMachine = setup({
  types: {
    context: {} as { x: number; y: number },
    events: {} as Ev
  },
  guards: {
    hasDelta: ({ event }) => event.dx !== 0 || event.dy !== 0
  }
}).createMachine({
  id: 'mouse',
  initial: 'idle',
  context: { x: 0, y: 0 },
  states: {
    idle: {
      on: {
        MOVE: {
          guard: 'hasDelta',
          actions: assign({
            x: ({ context, event }) => context.x + event.dx,
            y: ({ context, event }) => context.y + event.dy
          })
        }
      }
    }
  }
});
```

Swap positional args for destructuring; everything else stays the same.

```typescript
import { setup, assign } from 'xstate';

interface Item { readonly id: string; readonly price: number }

type Ev = { type: 'ADD'; item: Item; price: number };

export const listMachine = setup({
  types: {
    context: {} as { list: readonly Item[]; total: number },
    events: {} as Ev
  }
}).createMachine({
  id: 'list',
  context: { list: [], total: 0 },
  initial: 'active',
  states: {
    active: {
      on: {
        ADD: {
          actions: assign({
            list:  ({ context, event }) => [...context.list, event.item],
            total: ({ context, event }) => context.total + event.price
          })
        }
      }
    }
  }
});
```

