```typescript
import { setup, assign, fromPromise } from 'xstate';

interface AuthInput  { readonly user: string; readonly pass: string }
interface AuthOutput { readonly token: string }

type Ev =
  | { type: 'SET_USER'; v: string }
  | { type: 'SET_PASS'; v: string }
  | { type: 'SUBMIT' };

export const loginMachine = setup({
  types: {
    context: {} as { user: string; pass: string; error: Error | null },
    events: {} as Ev
  },
  guards: {
    canSubmit: ({ context }) => context.user.length > 0 && context.pass.length > 0
  },
  actors: {
    authenticate: fromPromise<AuthOutput, AuthInput>(async ({ input }) => {
      const r = await fetch('/auth', { method: 'POST', body: JSON.stringify(input) });
      if (!r.ok) throw new Error('bad');
      return (await r.json()) as AuthOutput;
    })
  }
}).createMachine({
  id: 'login',
  initial: 'idle',
  context: { user: '', pass: '', error: null },
  states: {
    idle: {
      on: {
        SET_USER: { actions: assign({ user: ({ event }) => event.v }) },
        SET_PASS: { actions: assign({ pass: ({ event }) => event.v }) },
        SUBMIT:   { target: 'auth', guard: 'canSubmit' }
      }
    },
    auth: {
      invoke: {
        src: 'authenticate',
        input: ({ context }) => ({ user: context.user, pass: context.pass }),
        onDone: 'success',
        onError: {
          target: 'idle',
          actions: assign({ error: ({ event }) => event.error as Error })
        }
      }
    },
    success: { type: 'final' }
  }
});
```

